const webhook = $json.body ?? {};
const entries = Array.isArray(webhook.entry) ? webhook.entry : [];
const output = [];

for (const entry of entries) {
  const pageId = String(entry.id ?? '').trim();
  const entryTime = Number(entry.time ?? 0);
  const messagingList = Array.isArray(entry.messaging) ? entry.messaging : [];

  for (let index = 0; index < messagingList.length; index += 1) {
    const messaging = messagingList[index] ?? {};
    const senderId = String(messaging.sender?.id ?? '').trim();
    const recipientId = String(messaging.recipient?.id ?? '').trim();

    const hasRead = !!messaging.read;
    const hasDelivery = !!messaging.delivery;
    const hasReaction = !!messaging.reaction;
    const hasPostback = !!messaging.postback;
    const hasMessage = !!messaging.message && typeof messaging.message === 'object';

    if (hasRead || hasDelivery || hasReaction || hasPostback) {
      continue;
    }

    if (!hasMessage) {
      continue;
    }

    const message = messaging.message;
    const isEcho = Boolean(message.is_echo);

    if (isEcho || (senderId && pageId && senderId === pageId)) {
      continue;
    }

    const text = String(message.text ?? '').trim();
    const attachments = Array.isArray(message.attachments) ? message.attachments : [];
    const imageAttachments = attachments.filter((item) => item?.type === 'image');
    const imageUrls = imageAttachments
      .map((item) => String(item?.payload?.url ?? '').trim())
      .filter(Boolean);

    if (!text && imageUrls.length === 0) {
      continue;
    }

    const eventTimestamp = Number(messaging.timestamp ?? 0);
    const diff = entryTime && eventTimestamp ? entryTime - eventTimestamp : 0;
    const fallbackMid = [pageId, senderId, eventTimestamp || Date.now(), index].join(':');
    const mid = String(message.mid ?? fallbackMid).trim();

    output.push({
      json: {
        channel: 'facebook',
        event_type: 'message',
        page_id: pageId,
        sender_id: senderId,
        recipient_id: recipientId,
        source_message_id: mid,
        message_text: text,
        has_image_attachment: imageUrls.length > 0,
        image_url: imageUrls[0] || '',
        image_urls: imageUrls,
        attachment_count: imageUrls.length,
        raw_attachments: imageAttachments,
        timeDiffms: diff,
        isValid: !!senderId && !!recipientId,
        event_timestamp_iso: eventTimestamp
          ? new Date(eventTimestamp).toISOString()
          : new Date().toISOString(),
        raw_event: {
          entry_id: pageId,
          entry_time: entryTime,
          messaging,
        },
      },
    });
  }
}

return output.length
  ? output
  : [{ json: { isValid: false, event_type: 'ignored', skip_reason: 'no_customer_message_events' } }];

const parseArray = (value) => {
  if (Array.isArray(value)) return value.map((item) => String(item || '').trim()).filter(Boolean);
  if (typeof value === 'string') {
    try {
      const parsed = JSON.parse(value);
      if (Array.isArray(parsed)) {
        return parsed.map((item) => String(item || '').trim()).filter(Boolean);
      }
    } catch {}
  }
  return [];
};

const dedupeLines = (value) => {
  const seen = new Set();
  return String(value || '')
    .split(/\n+/)
    .map((item) => String(item || '').trim())
    .filter(Boolean)
    .filter((line) => {
      const key = line.toLowerCase();
      if (seen.has(key)) return false;
      seen.add(key);
      return true;
    })
    .join('\n');
};

const imageUrls = parseArray($json.image_urls);
const firstImage = imageUrls.find(Boolean) || '';

return [{
  json: {
    channel: $json.channel,
    page_id: $json.page_id,
    sender_id: $json.sender_id,
    message_text: dedupeLines($json.merged_text),
    has_image_attachment: imageUrls.length > 0,
    image_url: firstImage,
    image_urls: imageUrls,
    attachment_count: imageUrls.length,
    fragment_count: Number($json.fragment_count || 0),
    buffer_version: Number($json.buffer_version || 0),
    source_message_id: String($json.last_mid || ''),
    first_event_at: $json.first_event_at,
    last_event_at: $json.last_event_at,
    is_buffered: true,
  },
}];

const normalize = (value) => String(value || '')
  .normalize('NFD')
  .replace(/[đĐ]/g, 'd')
  .replace(/[\u0300-\u036f]/g, '')
  .toLowerCase()
  .replace(/[^a-z0-9\s]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const STOP_WORDS = new Set([
  'anh', 'ban', 'ben', 'chi', 'cho', 'co', 'con', 'dang', 'dat', 'de', 'di', 'do', 'doi', 'duoc', 'em', 'form',
  'giup', 'gui', 'hang', 'khac', 'khong', 'kia', 'lay', 'la', 'loai', 'mau', 'minh', 'mot',
  'muon', 'nao', 'nay', 'ngoai', 'nha', 'nhe', 'nhu', 'noi', 'qua', 'ra', 'roi', 'san', 'shop', 'size',
  'so', 'tai', 'tay', 'the', 'thao', 'thay', 'thun', 'toi', 'va', 'voi', 'xem', 'xin', 'ao',
  'dong', 'ho', 'gps', 'giay', 'quan', 'pham', 'silicone', 'green', 'brown', 'dark', 'grey',
  'black', 'white', 'nam', 'nu', 'main', 'pace', 'nomad'
]);

const tokenizeMeaningful = (value) => Array.from(new Set(
  normalize(value)
    .split(' ')
    .filter((token) => token && token.length >= 3 && !STOP_WORDS.has(token) && !/^\d+$/.test(token))
));

const messageText = String($json.message_text || $json.customer_message || '').trim();
const normalizedText = normalize(messageText);
const prevProducts = String($json.prev_products_interested || $json.products_interested || '').trim();
const prevNeedSummary = String($json.prev_need_summary || $json.need_summary || '').trim();
const prevFullname = String($json.prev_fullname || $json.fullname || '').trim();
const prevPhone = String($json.prev_phone || $json.phone || '').trim();
const prevAddress = String($json.prev_address || $json.address || '').trim();

const explicitResetPatterns = [
  /san pham khac/,
  /mau khac/,
  /y toi muon dat san pham khac/,
  /toi muon dat san pham khac/,
  /doi sang/,
  /chuyen sang/,
  /thay vi/,
  /khong phai (?:cai )?(?:do|nay)/,
  /ngoai ra/,
  /con [a-z0-9 ]*khac khong/,
  /co [a-z0-9 ]*khac khong/,
  /gui [a-z0-9 ]*khac/,
  /xem [a-z0-9 ]*khac/,
];

const productSearchSignal = (Boolean(normalizedText) && [
  /ao\b/,
  /dong ho/,
  /giay\b/,
  /quan\b/,
  /san pham/,
  /mau\b/,
  /size\b/,
  /form\b/,
  /catalog/,
  /norda/,
  /coros/,
  /altra/,
  /thun\b/,
].some((pattern) => pattern.test(normalizedText))) || Boolean($json.has_image_attachment);

const prevProductTokens = tokenizeMeaningful(prevProducts);
const messageTopicTokens = tokenizeMeaningful(messageText);
const overlapCount = messageTopicTokens.filter((token) => prevProductTokens.includes(token)).length;
const explicitReset = explicitResetPatterns.some((pattern) => pattern.test(normalizedText));
const mentionsDifferentProduct = Boolean(prevProductTokens.length) && Boolean(messageTopicTokens.length) && productSearchSignal && overlapCount === 0;
const genericCatalogRefresh = Boolean(prevProductTokens.length) && /(san pham|mau|catalog|lookbook)/.test(normalizedText) && messageTopicTokens.length === 0;
const conversationReset = explicitReset || mentionsDifferentProduct || genericCatalogRefresh;
const conversationResetReason = explicitReset
  ? 'explicit_new_product_request'
  : (mentionsDifferentProduct ? 'new_topic_vs_previous_product' : (genericCatalogRefresh ? 'generic_catalog_refresh' : ''));
const browseProductsSignal = productSearchSignal && [
  /dang co/,
  /co san pham/,
  /san pham nao/,
  /co mau/,
  /mau nao/,
  /co dong/,
  /co loai/,
  /goi y/,
  /tu van/,
  /phu hop/,
  /tim [a-z0-9 ]*mau/,
].some((pattern) => pattern.test(normalizedText));

const baseSessionKey = [
  String($json.channel || 'chat').trim() || 'chat',
  String($json.page_id || $json.group_id || $json.oa_id || 'main').trim() || 'main',
  String($json.sender_id || $json.uid || $json.user_id || '').trim(),
].join(':');

let topicTokens = prevProductTokens;
if (conversationReset) {
  topicTokens = messageTopicTokens.length > 0 ? messageTopicTokens : [];
} else if (!topicTokens.length && messageTopicTokens.length > 0) {
  topicTokens = messageTopicTokens;
}

let memoryTopic = topicTokens.slice(0, 4).join('-');
if (!memoryTopic) {
  const fallback = String($json.source_message_id || $json.buffer_version || 'main')
    .toLowerCase()
    .replace(/[^a-z0-9]/g, '')
    .slice(-16) || 'main';
  memoryTopic = conversationReset ? `fresh-${fallback}` : 'main';
}

return [{
  json: {
    ...$json,
    conversation_reset: conversationReset,
    conversation_reset_reason: conversationResetReason,
    product_search_signal: productSearchSignal,
    browse_products_signal: browseProductsSignal,
    prompt_prev_customer_stage: conversationReset ? 'new' : String($json.prev_customer_stage || 'new'),
    prompt_prev_lead_status: conversationReset ? 'unknown' : String($json.prev_lead_status || 'unknown'),
    prompt_prev_need_summary: conversationReset ? '' : prevNeedSummary,
    prompt_prev_products_interested: conversationReset ? '' : prevProducts,
    prompt_known_fullname: conversationReset ? '' : prevFullname,
    prompt_known_phone: conversationReset ? '' : prevPhone,
    prompt_known_address: conversationReset ? '' : prevAddress,
    memory_scope: `${baseSessionKey}:topic:${memoryTopic}`,
    message_topic_tokens: messageTopicTokens.join(', '),
    prev_product_tokens: prevProductTokens.join(', '),
  },
}];

