parameters.jsCode:
const input = $input.first().json ?? {};

const CUSTOMER_STAGES = new Set([
  'new',
  'discovering',
  'quoted',
  'qualified',
  'waiting_phone',
  'handoff_ready',
  'cold',
]);

const LEAD_STATUSES = new Set([
  'unknown',
  'interested',
  'qualified',
  'not_interested',
  'inactive',
]);

function asString(value) {
  if (value === null || value === undefined) return '';
  return String(value).trim();
}

function asBoolean(value) {
  if (typeof value === 'boolean') return value;
  if (typeof value === 'number') return value !== 0;
  const text = asString(value).toLowerCase();
  if (['true', '1', 'yes', 'y'].includes(text)) return true;
  if (['false', '0', 'no', 'n', ''].includes(text)) return false;
  return false;
}

function asNumber(value, fallback = 0) {
  const num = Number(value);
  return Number.isFinite(num) ? num : fallback;
}

function normalizeIntentScore(value) {
  let score = asNumber(value, 0);
  if (score > 0 && score <= 1) score *= 100;
  score = Math.max(0, Math.min(100, score));
  return Math.round(score);
}

function stripCodeFence(text) {
  const raw = asString(text);
  const fenced = raw.match(/```(?:json)?\s*([\s\S]*?)```/i);
  return fenced ? fenced[1].trim() : raw;
}

function extractFirstJsonObject(text) {
  const raw = asString(text);
  const start = raw.indexOf('{');
  if (start === -1) return '';

  let depth = 0;
  let inString = false;
  let escaped = false;

  for (let i = start; i < raw.length; i += 1) {
    const ch = raw[i];

    if (escaped) {
      escaped = false;
      continue;
    }

    if (ch === '\\') {
      escaped = true;
      continue;
    }

    if (ch === '"') {
      inString = !inString;
      continue;
    }

    if (inString) continue;

    if (ch === '{') depth += 1;
    if (ch === '}') depth -= 1;

    if (depth === 0) {
      return raw.slice(start, i + 1);
    }
  }

  return '';
}

function parseJsonLike(rawValue) {
  if (rawValue && typeof rawValue === 'object') return rawValue;

  const text = stripCodeFence(rawValue);
  if (!text) throw new Error('empty_output');

  try {
    return JSON.parse(text);
  } catch (error) {
    const extracted = extractFirstJsonObject(text);
    if (!extracted) throw error;
    return JSON.parse(extracted);
  }
}

function unwrapPayload(value) {
  if (!value || typeof value !== 'object' || Array.isArray(value)) return value;

  if (value.output && typeof value.output === 'object' && !Array.isArray(value.output)) {
    return value.output;
  }

  if (value.data && typeof value.data === 'object' && !Array.isArray(value.data)) {
    return value.data;
  }

  if (value.result && typeof value.result === 'object' && !Array.isArray(value.result)) {
    return value.result;
  }

  return value;
}

function normalizeStage(value) {
  const stage = asString(value);
  return CUSTOMER_STAGES.has(stage) ? stage : 'new';
}

function normalizeLeadStatus(value) {
  const status = asString(value);
  return LEAD_STATUSES.has(status) ? status : 'unknown';
}

function normalizeProduct(item) {
  const source = item && typeof item === 'object' ? item : {};
  return {
    title: asString(source.title),
    variant: asString(source.variant),
    size: asString(source.size),
    quantity: Math.max(1, asNumber(source.quantity, 1)),
    price: asString(source.price),
    image: asString(source.image),
    website_url: asString(source.website_url),
  };
}

function formatReplyMessage(value) {
  const raw = asString(value);
  if (!raw) return '';

  const compactText = raw
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n')
    .replace(/[ \t]+\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();

  if (!compactText) return '';

  const splitSentences = (text) => {
    const parts = text.split(/(?<=[.!?])\s+/).map((item) => item.trim()).filter(Boolean);
    return parts.length > 0 ? parts : [text];
  };

  const paragraphs = compactText
    .split(/\n{2,}/)
    .map((block) => block.trim())
    .filter(Boolean)
    .flatMap((block) => {
      const prepared = block
        .replace(/\n+/g, ' ')
        .replace(/\s+/g, ' ')
        .replace(/([.!?])\s+(?=(?:Dạ|Da|Em|Anh\/chị|Anh\/chi|Hiện|Hien|Nếu|Neu|Ngoài ra|Ngoai ra|Mình|Minh|Để|De)\b)/g, '$1\n')
        .replace(/:\s+(?=\S)/g, ':\n')
        .trim();

      if (!prepared) return [];
      if (prepared.includes('\n')) {
        return prepared.split(/\n+/).map((line) => line.trim()).filter(Boolean);
      }
      if (/^([-*•]|\d+\.)\s/.test(prepared)) return [prepared];

      const sentences = splitSentences(prepared);
      return sentences.length > 1 ? sentences : [prepared];
    });

  return paragraphs.join('\n\n').replace(/\n{3,}/g, '\n\n').slice(0, 1500);
}

const rawCandidate =
  input.output ??
  input.text ??
  input.response ??
  input.result ??
  input.answer ??
  input;

let parsed = {};
let parseError = '';

try {
  parsed = unwrapPayload(parseJsonLike(rawCandidate));
} catch (error) {
  parseError = error.message || 'parse_failed';
  parsed = {};
}

const rawText =
  typeof rawCandidate === 'string'
    ? rawCandidate
    : JSON.stringify(rawCandidate);

const product = Array.isArray(parsed.product)
  ? parsed.product.map(normalizeProduct).slice(0, 5)
  : [];

const normalized = {
  fullname: asString(parsed.fullname),
  phone: asString(parsed.phone),
  address: asString(parsed.address),
  products_interested: asString(parsed.products_interested),
  need_summary: asString(parsed.need_summary),
  customer_stage: normalizeStage(parsed.customer_stage),
  lead_status: normalizeLeadStatus(parsed.lead_status),
  intent_score: normalizeIntentScore(parsed.intent_score),
  ask_for_phone_now: asBoolean(parsed.ask_for_phone_now),
  has_clear_need: asBoolean(parsed.has_clear_need),
  handoff_ready: asBoolean(parsed.handoff_ready),
  handoff_reason: asString(parsed.handoff_reason),
  message: formatReplyMessage(asString(parsed.message) || asString(rawText).slice(0, 1000)),
  product,
};

if (!normalized.products_interested && normalized.product.length > 0) {
  normalized.products_interested = normalized.product
    .map((item) => item.title)
    .filter(Boolean)
    .slice(0, 3)
    .join(', ');
}

if (!normalized.need_summary && normalized.products_interested) {
  normalized.need_summary = `Khach dang quan tam ${normalized.products_interested}`.slice(0, 500);
}

return [
  {
    json: {
      output: normalized,
      parse_status: parseError ? 'fallback' : 'ok',
      parse_error: parseError,
      raw_output_text: rawText,
    },
  },
];

